Here are the public test cases for feature1_swap_policy:
{
  "description": "Resolve an image-swap mode keyword into its canonical mode name. Recognized keywords echo back their canonical name. An unrecognized keyword falls back to the safe default mode and is additionally reported as an error together with the offending input.",
  "cases": [
    {
      "input": {
        "op": "swap_policy",
        "value": "always"
      },
      "expected_output": "policy=always\n"
    },
    {
      "input": {
        "op": "swap_policy",
        "value": "exists"
      },
      "expected_output": "policy=exists\n"
    },
    {
      "input": {
        "op": "swap_policy",
        "value": "random-non-existent"
      },
      "expected_output": "policy=exists\nerror=unknown_swap_policy\ninput=random-non-existent\n"
    }
  ]
}

