Here are the public test cases for feature3_config_filters:
{
  "description": "Parse a YAML configuration document and report the ordered list of container-selection expressions declared under the source filters section. An empty document yields zero filters.",
  "cases": [
    {
      "input": {
        "op": "parse_config",
        "yaml": ""
      },
      "expected_output": "filters=0\n"
    },
    {
      "input": {
        "op": "parse_config",
        "yaml": "source:\n  filters:\n    - jmespath: \"obj.metadata.namespace == 'kube-system'\"\n    - jmespath: \"obj.metadata.namespace != 'playground'\"\n"
      },
      "expected_output": "filters=2\nfilter[0].jmespath=obj.metadata.namespace == 'kube-system'\nfilter[1].jmespath=obj.metadata.namespace != 'playground'\n"
    }
  ]
}

Here are the public test cases for feature4_selection_predicate:
{
  "description": "Evaluate a single selection expression against a context built from a pod (namespace) and the container currently under consideration. A boolean-true result matches; a boolean-false result does not match; an expression that errors or yields a non-boolean value does not match and reports the neutral reason category.",
  "cases": [
    {
      "input": {
        "op": "filter_match",
        "namespace": "kube-system",
        "container": {
          "name": "nginx",
          "image": "nginx:latest"
        },
        "expression": "obj.metadata.namespace == 'kube-system'"
      },
      "expected_output": "namespace=kube-system\ncontainer=nginx\nexpression=obj.metadata.namespace == 'kube-system'\nmatch=true\n"
    },
    {
      "input": {
        "op": "filter_match",
        "namespace": "kube-system",
        "container": {
          "name": "nginx",
          "image": "nginx:latest"
        },
        "expression": "obj.metadata.namespace != 'kube-system'"
      },
      "expected_output": "namespace=kube-system\ncontainer=nginx\nexpression=obj.metadata.namespace != 'kube-system'\nmatch=false\n"
    },
    {
      "input": {
        "op": "filter_match",
        "namespace": "kube-system",
        "container": {
          "name": "nginx",
          "image": "nginx:latest"
        },
        "expression": "container.name == 'nginx'"
      },
      "expected_output": "namespace=kube-system\ncontainer=nginx\nexpression=container.name == 'nginx'\nmatch=true\n"
    },
    {
      "input": {
        "op": "filter_match",
        "namespace": "kube-system",
        "container": {
          "name": "nginx",
          "image": "nginx:latest"
        },
        "expression": "obj"
      },
      "expected_output": "namespace=kube-system\ncontainer=nginx\nexpression=obj\nmatch=false\nreason=non_boolean_result\n"
    },
    {
      "input": {
        "op": "filter_match",
        "namespace": "kube-system",
        "container": {
          "name": "nginx",
          "image": "nginx:latest"
        },
        "expression": "."
      },
      "expected_output": "namespace=kube-system\ncontainer=nginx\nexpression=.\nmatch=false\nreason=evaluation_error\n"
    },
    {
      "input": {
        "op": "filter_match",
        "namespace": "kube-system",
        "container": {
          "name": "nginx",
          "image": "nginx:latest"
        },
        "expression": "contains(container.image, '.dkr.ecr.') && contains(container.image, '.amazonaws.com')"
      },
      "expected_output": "namespace=kube-system\ncontainer=nginx\nexpression=contains(container.image, '.dkr.ecr.') && contains(container.image, '.amazonaws.com')\nmatch=false\n"
    }
  ]
}

Here are the public test cases for feature5_1_secret_aggregation:
{
  "description": "Aggregate a set of named docker-config credential documents into a single merged JSON document. Each named secret is retained verbatim and the merged aggregate combines all keys.",
  "cases": [
    {
      "input": {
        "op": "aggregate_secrets",
        "secrets": [
          {
            "name": "foo",
            "data": "{\"foo\":\"123\"}"
          },
          {
            "name": "bar",
            "data": "{\"bar\":\"456\"}"
          }
        ]
      },
      "expected_output": "secret_count=2\nsecret[bar]={\"bar\":\"456\"}\nsecret[foo]={\"foo\":\"123\"}\naggregate={\"bar\":\"456\",\"foo\":\"123\"}\n"
    }
  ]
}

Here are the public test cases for feature5_2_secret_resolution:
{
  "description": "Resolve the set of docker-config pull-credential documents that apply to a pod. The cluster-backed resolver collects credentials referenced directly by the pod and by its service account, fetching each named secret once and producing the merged aggregate. The no-op resolver always yields an empty set.",
  "cases": [
    {
      "input": {
        "op": "resolve_pull_secrets",
        "mode": "noop",
        "namespace": "test-ns",
        "pod": {
          "name": "my-pod",
          "service_account_name": "my-service-account",
          "image_pull_secrets": [
            "my-pod-secret"
          ]
        }
      },
      "expected_output": "secret_count=0\naggregate={}\n"
    },
    {
      "input": {
        "op": "resolve_pull_secrets",
        "mode": "kubernetes",
        "namespace": "test-ns",
        "pod": {
          "name": "my-pod",
          "service_account_name": "my-service-account",
          "image_pull_secrets": [
            "my-pod-secret"
          ]
        },
        "service_account": {
          "name": "my-service-account",
          "image_pull_secrets": [
            "my-sa-secret"
          ]
        },
        "secrets": [
          {
            "name": "my-sa-secret",
            "data": "{\"auths\":{\"my-sa-secret.registry.example.com\":{\"username\":\"my-sa-secret\",\"password\":\"xxxxxxxxxxx\",\"email\":\"jdoe@example.com\",\"auth\":\"c3R...zE2\"}}}"
          },
          {
            "name": "my-pod-secret",
            "data": "{\"auths\":{\"my-pod-secret.registry.example.com\":{\"username\":\"my-sa-secret\",\"password\":\"xxxxxxxxxxx\",\"email\":\"jdoe@example.com\",\"auth\":\"c3R...zE2\"}}}"
          }
        ]
      },
      "expected_output": "secret_count=2\nsecret[my-pod-secret]={\"auths\":{\"my-pod-secret.registry.example.com\":{\"username\":\"my-sa-secret\",\"password\":\"xxxxxxxxxxx\",\"email\":\"jdoe@example.com\",\"auth\":\"c3R...zE2\"}}}\nsecret[my-sa-secret]={\"auths\":{\"my-sa-secret.registry.example.com\":{\"username\":\"my-sa-secret\",\"password\":\"xxxxxxxxxxx\",\"email\":\"jdoe@example.com\",\"auth\":\"c3R...zE2\"}}}\naggregate={\"auths\":{\"my-pod-secret.registry.example.com\":{\"auth\":\"c3R...zE2\",\"email\":\"jdoe@example.com\",\"password\":\"xxxxxxxxxxx\",\"username\":\"my-sa-secret\"},\"my-sa-secret.registry.example.com\":{\"auth\":\"c3R...zE2\",\"email\":\"jdoe@example.com\",\"password\":\"xxxxxxxxxxx\",\"username\":\"my-sa-secret\"}}}\n"
    }
  ]
}

